import requests

def handle_api_pagination(base_url, initial_params=None, page_param_name='page', page_size_param_name='page_size', default_page_size=100, data_key='data'):
    all_items = []
    current_page = 1

    params = initial_params.copy() if initial_params else {}
    params[page_size_param_name] = default_page_size

    while True:
        params[page_param_name] = current_page

        try:
            response = requests.get(base_url, params=params)
            response.raise_for_status() 

            page_data = response.json()

            items_on_page = page_data.get(data_key)

            if not isinstance(items_on_page, list):
                break 

            all_items.extend(items_on_page)

            if len(items_on_page) < default_page_size:
                break

            current_page += 1

        except requests.exceptions.RequestException:
            break
        except ValueError: 
            break

    return all_items
